"""
routes_order_sample2.py -- Object-oriented state machine approach (Gen 1 Sample 2)

Mutation strategy:
- OrderStateMachine class encapsulates all state transition logic
- VALID_TRANSITIONS as a class-level frozenset of (from, to) tuples
- TRANSITION_TIMESTAMPS maps target states to the DB column to set
- Stock operations inlined into state transition methods
- request.headers.get() for Idempotency-Key retrieval
- Idempotency via PaymentRequest model query
- db.session.get() for primary key lookups (SQLAlchemy 2.0 pattern)
- _success_response / _error_response helpers for consistent JSON envelope
"""

from flask import Blueprint, request, jsonify
from datetime import datetime
from models import db, Order, OrderItem, PaymentRequest, Product

order_bp = Blueprint('order_bp', __name__)


# ---------------------------------------------------------------------------
# Response helpers
# ---------------------------------------------------------------------------

def _success_response(data, status_code=200):
    return jsonify({"status": "ok", "data": data}), status_code


def _error_response(message, status_code=400):
    return jsonify({"status": "error", "message": message}), status_code


# ---------------------------------------------------------------------------
# Serialization helpers
# ---------------------------------------------------------------------------

_ORDER_FIELDS = (
    'id', 'user_id', 'status', 'total_amount', 'created_at',
    'paid_at', 'shipped_at', 'delivered_at', 'cancelled_at',
)

_ITEM_FIELDS = ('id', 'product_id', 'quantity', 'unit_price')


def _serialize_order(order, include_items=False):
    result = {}
    for key in _ORDER_FIELDS:
        val = getattr(order, key)
        if key == 'total_amount':
            val = float(val)
        else:
            val = _fmt_datetime(val)
        result[key] = val
    if include_items:
        result['items'] = [
            {k: getattr(item, k) for k in _ITEM_FIELDS}
            for item in order.items
        ]
    return result


def _serialize_orders(orders):
    return [_serialize_order(o) for o in orders]


def _fmt_datetime(value):
    """Convert datetime to ISO string, pass through None."""
    if value is None:
        return None
    return value.isoformat() if hasattr(value, 'isoformat') else str(value)


# ---------------------------------------------------------------------------
# Order State Machine
# ---------------------------------------------------------------------------

class OrderStateMachine:
    """Encapsulates order state transitions and associated side-effects."""

    VALID_TRANSITIONS = frozenset({
        ('pending', 'paid'),
        ('paid', 'shipped'),
        ('shipped', 'delivered'),
        ('pending', 'cancelled'),
        ('paid', 'cancelled'),
    })

    # Maps target status -> timestamp attribute name on the Order model
    TRANSITION_TIMESTAMPS = {
        'paid': 'paid_at',
        'shipped': 'shipped_at',
        'delivered': 'delivered_at',
        'cancelled': 'cancelled_at',
    }

    def __init__(self, order):
        self.order = order

    @property
    def current_status(self):
        return self.order.status

    def can_transition_to(self, target):
        return (self.current_status, target) in self.VALID_TRANSITIONS

    def _apply_transition(self, target):
        """Set status and record the timestamp for the transition."""
        self.order.status = target
        ts_attr = self.TRANSITION_TIMESTAMPS.get(target)
        if ts_attr is not None:
            setattr(self.order, ts_attr, datetime.utcnow())

    def transition_to(self, target):
        """Attempt a state transition. Returns (success, error_message)."""
        if not self.can_transition_to(target):
            return False, (
                f"Invalid transition: {self.current_status} -> {target}"
            )
        self._apply_transition(target)
        return True, None

    def pay(self, idempotency_key):
        """Execute payment: deduct stock, record PaymentRequest, transition."""
        # Idempotency check: return existing result if key was seen
        existing = PaymentRequest.query.filter_by(
            idempotency_key=idempotency_key
        ).first()
        if existing is not None:
            return existing  # idempotent -- caller should return the order

        ok, err = self.transition_to('paid')
        if not ok:
            return None, err

        # Deduct stock for each order item
        for item in self.order.items:
            product = db.session.get(Product, item.product_id)
            product.stock -= item.quantity

        # Record the idempotency key
        payment = PaymentRequest(
            order_id=self.order.id,
            idempotency_key=idempotency_key,
            status='completed',
        )
        db.session.add(payment)
        return payment

    def cancel(self):
        """Cancel the order. If paid, restore stock."""
        was_paid = self.current_status == 'paid'

        ok, err = self.transition_to('cancelled')
        if not ok:
            return False, err

        # Roll back inventory if the order had been paid
        if was_paid:
            for item in self.order.items:
                product = db.session.get(Product, item.product_id)
                product.stock += item.quantity

        return True, None

    def ship(self):
        return self.transition_to('shipped')

    def deliver(self):
        return self.transition_to('delivered')


# ---------------------------------------------------------------------------
# Route handlers
# ---------------------------------------------------------------------------

@order_bp.route('/orders', methods=['POST'])
def create_order():
    """POST /orders -- Create a new order with items."""
    try:
        payload = request.get_json(silent=True)
        if payload is None:
            return _error_response("Request body must be valid JSON", 400)

        user_id = payload.get('user_id')
        items_data = payload.get('items')

        if not user_id:
            return _error_response("Missing required field: user_id", 400)
        if not items_data or not isinstance(items_data, list):
            return _error_response("Missing or invalid field: items", 400)

        # Validate products and compute total
        order_items = []
        total_amount = 0.0

        for idx, item in enumerate(items_data):
            product_id = item.get('product_id')
            quantity = item.get('quantity')

            if product_id is None or quantity is None:
                return _error_response(
                    f"Item at index {idx} missing product_id or quantity", 400
                )

            product = db.session.get(Product, product_id)
            if product is None:
                return _error_response(
                    f"Product {product_id} not found", 400
                )

            if quantity <= 0:
                return _error_response(
                    f"Quantity must be positive for product {product_id}", 400
                )

            if product.stock < quantity:
                return _error_response(
                    f"Insufficient stock for product '{product.name}' "
                    f"(requested {quantity}, available {product.stock})", 400
                )

            total_amount += product.price * quantity
            order_items.append((product, int(quantity)))

        # Create Order + OrderItem records
        order = Order(user_id=user_id, status='pending', total_amount=total_amount)
        db.session.add(order)
        db.session.flush()  # get order.id before creating items

        for product, quantity in order_items:
            oi = OrderItem(
                order_id=order.id,
                product_id=product.id,
                quantity=quantity,
                unit_price=product.price,
            )
            db.session.add(oi)

        db.session.commit()
        return _success_response(_serialize_order(order), 201)

    except Exception as exc:
        db.session.rollback()
        return _error_response(str(exc), 400)


@order_bp.route('/orders/<int:order_id>', methods=['GET'])
def get_order(order_id):
    """GET /orders/<id> -- Retrieve a single order with its items."""
    try:
        order = db.session.get(Order, order_id)
        if order is None:
            return _error_response(f"Order {order_id} not found", 404)
        return _success_response(_serialize_order(order, include_items=True))
    except Exception as exc:
        return _error_response(str(exc), 500)


@order_bp.route('/orders', methods=['GET'])
def list_orders():
    """GET /orders -- List orders, optionally filtered by user_id and/or status."""
    try:
        query = Order.query
        user_id = request.args.get('user_id')
        status = request.args.get('status')

        if user_id is not None:
            query = query.filter(Order.user_id == user_id)
        if status is not None:
            query = query.filter(Order.status == status)

        orders = query.all()
        return _success_response(_serialize_orders(orders))
    except Exception as exc:
        return _error_response(str(exc), 500)


@order_bp.route('/orders/<int:order_id>/pay', methods=['POST'])
def pay_order(order_id):
    """POST /orders/<id>/pay -- Pay for order (pending -> paid).

    Requires Idempotency-Key header. Deducts stock. Idempotent on duplicate key.
    """
    try:
        # Idempotency-Key is mandatory
        idempotency_key = request.headers.get('Idempotency-Key')
        if not idempotency_key:
            return _error_response("Missing required header: Idempotency-Key", 400)

        order = db.session.get(Order, order_id)
        if order is None:
            return _error_response(f"Order {order_id} not found", 404)

        sm = OrderStateMachine(order)
        result = sm.pay(idempotency_key)

        # Idempotent path: key already processed
        if result is not None and not isinstance(result, tuple):
            db.session.commit()
            return _success_response(_serialize_order(order))

        # Error path: (None, error_message)
        if isinstance(result, tuple):
            return _error_response(result[1], 409)

        db.session.commit()
        return _success_response(_serialize_order(order))

    except Exception as exc:
        db.session.rollback()
        return _error_response(str(exc), 500)


@order_bp.route('/orders/<int:order_id>/ship', methods=['POST'])
def ship_order(order_id):
    """POST /orders/<id>/ship -- Ship order (paid -> shipped)."""
    try:
        order = db.session.get(Order, order_id)
        if order is None:
            return _error_response(f"Order {order_id} not found", 404)

